const allItems = $input.all();

const slowQ   = allItems.filter(i => i.json.avg_cpu_ms !== undefined);
const missIdx = allItems.filter(i => i.json.improvement_score !== undefined);
const fragIdx = allItems.filter(i => i.json.fragmentation_pct !== undefined);
const waits   = allItems.filter(i => i.json.pct_of_total !== undefined);

const issues = [];

for (const row of slowQ) {
  const d = row.json;
  if (d.avg_cpu_ms > 500) {
    issues.push({
      severity: d.avg_cpu_ms > 3000 ? 'critical' : 'warning',
      type: 'Slow query',
      detail: `avg ${d.avg_cpu_ms}ms CPU — ${String(d.query_text).slice(0, 100)}...`,
    });
  }
}

for (const row of missIdx) {
  const d = row.json;
  if (d.improvement_score > 100000) {
    issues.push({
      severity: d.improvement_score > 500000 ? 'critical' : 'warning',
      type: 'Missing index',
      detail: `${d.table_name} — score ${d.improvement_score}, impact ${d.avg_impact_pct}%`,
    });
  }
}

for (const row of fragIdx) {
  const d = row.json;
  if (d.recommendation === 'REBUILD' || d.recommendation === 'REORGANIZE') {
    issues.push({
      severity: d.recommendation === 'REBUILD' ? 'critical' : 'warning',
      type: `Index ${d.recommendation.toLowerCase()}`,
      detail: `${d.table_name}.${d.index_name} — ${d.fragmentation_pct}% fragmented`,
    });
  }
}

for (const row of waits.slice(0, 3)) {
  const d = row.json;
  if (d.pct_of_total > 20) {
    issues.push({
      severity: d.pct_of_total > 40 ? 'critical' : 'warning',
      type: 'High wait type',
      detail: `${d.wait_type} — ${d.pct_of_total}% of all waits (${d.wait_time_sec}s)`,
    });
  }
}

const hasCritical = issues.some(i => i.severity === 'critical');
const hasIssues   = issues.length > 0;

const rows = issues.map(i => `
  <tr>
    <td style="padding:6px 10px;color:${
      i.severity === 'critical' ? '#A32D2D' : '#854F0B'
    };font-weight:500">${i.severity.toUpperCase()}</td>
    <td style="padding:6px 10px">${i.type}</td>
    <td style="padding:6px 10px;font-family:monospace;font-size:12px">${i.detail}</td>
  </tr>`).join('');

