    ${issues.some(i=>i.type==='Index reorganize') ?'<div class="rec-item">Run ALTER INDEX ... REORGANIZE on indexes between 10–30%</div>':''}
    ${issues.some(i=>i.type==='Missing index')    ?'<div class="rec-item">Review missing index suggestions — create highest-score indexes first</div>':''}
    ${issues.some(i=>i.type==='Slow query')       ?'<div class="rec-item">Inspect slow query execution plans in SSMS</div>':''}
